import { useState } from "react";
import {
  BarChart3, Package, Scale, Thermometer, Boxes, BarChart2,
  Users, LogOut, UserCircle, RefreshCw, Menu, Building2, Truck,
  GitBranch, ClipboardList, Send, Truck as TruckIcon, Settings, Shield, Printer
} from "lucide-react";
import { C, ROL_COLORS } from "../constants/theme";
import { useAuth } from "../context/AuthContext";
import { useResponsive } from "../hooks/useResponsive";

const LOGO = "data:image/jpeg;base64,";

const NAV = [
  { id:"dashboard",    label:"Dashboard",          icon:BarChart3,    grupo:"PRINCIPAL" },
  { id:"lotes",        label:"Lotes",               icon:Package,      grupo:"PRODUCCIÓN", num:1 },
  { id:"recepcion",    label:"Recepción Camión",    icon:TruckIcon,    num:2 },
  { id:"pesajes",      label:"Pesajes",             icon:Scale,        num:3 },
  { id:"cargarcarros", label:"Cargar Carros",       icon:Truck,        num:4 },
  { id:"tuneles",      label:"Administración de Cajas y Túneles",    icon:Thermometer, num:5 },
  { id:"inventario",   label:"Inventario",          icon:Boxes,        grupo:"BODEGA" },
  { id:"despachos",    label:"Despachos",           icon:Send },
  { id:"etiquetas",    label:"Imprimir Etiquetas",  icon:Printer },
  { id:"trazabilidad", label:"Trazabilidad",        icon:GitBranch,    grupo:"SEGUIMIENTO" },
  { id:"reportes",     label:"Reportes",            icon:BarChart2 },
  { id:"proveedores",  label:"Proveedores",         icon:Building2,    grupo:"ADMINISTRACIÓN", nivelMin:3 },
  { id:"conductores",  label:"Conductores",         icon:Truck,        nivelMin:3 },
  { id:"configuracion",label:"Configuración",       icon:Settings,     nivelMin:3 },
  { id:"haccp",        label:"Formularios HACCP",   icon:ClipboardList, grupo:"CALIDAD" },
  { id:"audit",        label:"Historial",           icon:ClipboardList,adminOnly:true },
  { id:"usuarios",     label:"Usuarios",            icon:Users,        adminOnly:true },
];

export const Navbar = ({ vista, onNavegar }) => {
  const { usuario, logout, esAdmin } = useAuth();
  const { isMobile } = useResponsive();
  const [abierto, setAbierto] = useState(false);

  const items = NAV.filter(n => {
    if (n.adminOnly) return esAdmin;
    if (n.nivelMin) return (usuario?.nivel||0) >= n.nivelMin;
    return true;
  });
  const ir = id => { onNavegar(id); setAbierto(false); };

  return (
    <>
      {abierto&&<div onClick={()=>setAbierto(false)} style={{position:"fixed",inset:0,background:"rgba(10,26,74,.55)",zIndex:49,backdropFilter:"blur(2px)"}}/>}
      <aside style={{
        position:"fixed",top:0,left:0,height:"100vh",
        width: isMobile?"85vw":240,maxWidth:280,zIndex:50,
        background:`linear-gradient(180deg,${C.blue900} 0%,${C.blue800} 60%,${C.blue700} 100%)`,
        display:"flex",flexDirection:"column",
        transform:abierto?"translateX(0)":"translateX(-100%)",
        transition:"transform .28s cubic-bezier(.4,0,.2,1)",
        boxShadow:abierto?"8px 0 30px rgba(0,0,0,.4)":"none",
      }}>
        <div style={{padding:"18px 16px 12px",borderBottom:"1px solid rgba(255,255,255,.07)",display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:44,height:44,borderRadius:12,overflow:"hidden",background:"white",flexShrink:0}}>
            <img src={LOGO} alt="TR3S AL MAR" style={{width:"100%",height:"100%",objectFit:"contain",padding:3}}/>
          </div>
          <div style={{flex:1}}>
            <p style={{color:"white",fontWeight:800,fontSize:13}}>TR3S AL MAR</p>
            <p style={{color:"rgba(255,255,255,.3)",fontSize:9,fontWeight:600,letterSpacing:.6}}>PRODUCCIÓN v5</p>
          </div>
          <button onClick={()=>setAbierto(false)} style={{background:"none",border:"none",color:"rgba(255,255,255,.4)",cursor:"pointer",padding:4}}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>
        <nav style={{flex:1,padding:"8px 6px",display:"flex",flexDirection:"column",gap:1,overflowY:"auto",WebkitOverflowScrolling:"touch"}}>
          {items.map(item=>{
            const Icon=item.icon; const activo=vista===item.id;
            const esRecepcion = item.id==="recepcion";
            return (
              <div key={item.id}>
                {item.grupo&&<p style={{fontSize:9,color:"rgba(255,255,255,.2)",fontWeight:700,letterSpacing:1,textTransform:"uppercase",padding:"10px 14px 3px"}}>{item.grupo}</p>}
                <button onClick={()=>ir(item.id)} style={{
                  display:"flex",alignItems:"center",gap:10,
                  padding: isMobile?"12px 14px":"10px 14px",
                  borderRadius:11,border:"none",fontFamily:"inherit",
                  fontSize: isMobile?14:13,width:"100%",textAlign:"left",cursor:"pointer",transition:"all .15s",
                  background:activo?"rgba(255,255,255,.13)":esRecepcion?"rgba(255,200,100,.08)":"transparent",
                  color:activo?"white":esRecepcion?"#fcd34d":"rgba(255,255,255,.48)",fontWeight:activo?700:esRecepcion?600:500,
                  borderLeft:activo?"3px solid #60a5fa":esRecepcion?"3px solid #fcd34d55":"3px solid transparent",
                }}>
                  <Icon size={17} style={{flexShrink:0}}/>{item.num!=null&&<span style={{fontSize:10,fontWeight:700,minWidth:16,height:16,borderRadius:4,background:"rgba(255,255,255,.15)",color:"rgba(255,255,255,.7)",display:"inline-flex",alignItems:"center",justifyContent:"center",padding:"0 4px",marginRight:2,flexShrink:0}}>{item.num}</span>}{item.label}
                  {esRecepcion&&<span style={{marginLeft:"auto",fontSize:9,background:"#fcd34d",color:"#713f12",borderRadius:10,padding:"1px 6px",fontWeight:700}}>ENTRADA</span>}
                </button>
              </div>
            );
          })}
        </nav>
        <div style={{padding:"10px 12px",borderTop:"1px solid rgba(255,255,255,.07)"}}>
          <div style={{background:"rgba(255,255,255,.06)",borderRadius:12,padding:"10px 12px",border:"1px solid rgba(255,255,255,.08)",display:"flex",alignItems:"center",gap:9}}>
            <div style={{width:34,height:34,borderRadius:10,flexShrink:0,background:`${ROL_COLORS[usuario?.rol]||C.blue600}40`,border:`1px solid ${ROL_COLORS[usuario?.rol]||C.blue600}60`,display:"flex",alignItems:"center",justifyContent:"center"}}>
              <UserCircle size={18} color={ROL_COLORS[usuario?.rol]||"white"}/>
            </div>
            <div style={{flex:1,minWidth:0}}>
              <p style={{color:"white",fontSize:12,fontWeight:700,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{usuario?.nombre}</p>
              <span style={{padding:"1px 7px",borderRadius:20,fontSize:9,fontWeight:700,background:`${ROL_COLORS[usuario?.rol]||C.blue600}40`,color:ROL_COLORS[usuario?.rol]||C.blue300}}>{usuario?.rol}</span>
            </div>
            <button onClick={logout} style={{background:"rgba(255,255,255,.08)",border:"1px solid rgba(255,255,255,.12)",borderRadius:8,width:30,height:30,cursor:"pointer",color:"rgba(255,255,255,.5)",display:"flex",alignItems:"center",justifyContent:"center"}}><LogOut size={13}/></button>
          </div>
        </div>
      </aside>
      <header style={{
        background:C.blue800,borderBottom:`1px solid ${C.blue700}`,
        padding:"0 14px",height:54,display:"flex",alignItems:"center",gap:10,
        position:"sticky",top:0,zIndex:40,boxShadow:"0 2px 12px rgba(0,0,0,.2)",
      }}>
        <button onClick={()=>setAbierto(p=>!p)} style={{width:40,height:40,borderRadius:10,background:"rgba(255,255,255,.08)",border:"1px solid rgba(255,255,255,.12)",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",padding:0,flexShrink:0}}>
          <Menu size={18} color="white"/>
        </button>
        <div style={{width:26,height:26,borderRadius:7,overflow:"hidden",background:"white",flexShrink:0}}>
          <img src={LOGO} alt="" style={{width:"100%",height:"100%",objectFit:"contain",padding:2}}/>
        </div>
        {!isMobile&&<span style={{color:"white",fontWeight:800,fontSize:14}}>TR3S AL MAR</span>}
        {!isMobile&&<span style={{color:"rgba(255,255,255,.3)"}}>·</span>}
        <span style={{color:C.blue300,fontWeight:600,fontSize: isMobile?12:13,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
          {NAV.find(n=>n.id===vista)?.label}
        </span>
        <div style={{flex:1}}/>
      </header>
    </>
  );
};
